const body = $('PDF Request Webhook').item.json.body;
const insp = $('Fetch FireInspection').item.json;
const cust = $('Fetch Customer').item.json || {};
const site = $('Fetch Site').item.json || {};
const form_num = parseInt(body.form_num || 1);
const insp_id = body.inspection_id;

let contact = {};
try {
  const cr = $('Fetch Contact').item.json;
  const arr = Array.isArray(cr) ? cr : (cr && cr.data ? cr.data : []);
  contact = arr.find(c => c.is_primary) || arr[0] || {};
} catch (e) {}

let rawRows = [];
try {
  const rowsResp = $('Fetch Form Rows').item.json;
  if (Array.isArray(rowsResp)) rawRows = rowsResp;
  else if (rowsResp.data && Array.isArray(rowsResp.data)) rawRows = rowsResp.data;
} catch (e) {}

const common = {
  date: insp.inspection_date || new Date().toLocaleDateString('he-IL'),
  business_name: insp.customer_name || cust.name || '',
  business_type: cust.business_type || '',
  city: site.city || '',
  street: site.street || '',
  house_number: site.house_number || '',
  zip: site.zip || '',
  po_box: site.po_box || '',
  contact_name: contact.full_name || cust.contact_name || '',
  contact_role: contact.role || '',
  contact_phone: contact.phone || cust.phone || '',
  contact_email: contact.email || cust.email || '',
  vat_number: cust.vat_number || '',
  fire_file_number: insp.fire_file_number || site.fire_file_number || '',
  inspector_name: insp.inspector_name || '',
  inspector_id_number: insp.inspector_id_number || '',
  company_name: 'ר.אבוקה (1993) בע"מ',
  chk_zarnukim: insp.chk_zarnukim === true,
  chk_mitzmadim: insp.chk_mitzmadim === true,
  chk_maznakim: insp.chk_maznakim === true,
  chk_galgalon: insp.chk_galgalon === true,
  chk_acher: insp.chk_acher === true,
  acher_text: insp.acher_text || '',
};

const statusMap = { present: 'קיים', absent: 'לא קיים', na: '---' };
const inspTypeMap = { annual: 'שוטפת שנתית', major: 'יסודית', pressure: 'לחץ', major_and_pressure: 'יסודית+לחץ' };
const extTypeMap = { powder: 'אבקה', halon: 'הלוקרבון', water: 'מים', foam: 'קצף', co2: 'CO2' };

let rows = [];
if (form_num === 1) {
  rows = rawRows.map((r, i) => ({
    num: String(r.station_number || i + 1),
    location: r.location || '',
    hose: statusMap[r.hose_2inch] || '',
    nozzle: statusMap[r.nozzle_2inch] || '',
    cabinet: statusMap[r.equipment_cabinet] || '',
    reel: statusMap[r.hose_reel] || '',
    notes: r.notes || '',
  }));
} else if (form_num === 2) {
  rows = rawRows.map((r, i) => ({
    num: String(i + 1),
    id: r.serial_number || '',
    location: r.location || '',
    type: extTypeMap[r.extinguisher_type] || r.extinguisher_type || '',
    size_kg: String(r.size_kg || ''),
    manufacturer: r.manufacturer || '',
    next_major: r.next_major_inspection || '',
    next_pressure: r.next_pressure_test || '',
    ok: r.is_functional === true ? '✓' : '',
    not_ok: r.is_functional === false ? '✓' : '',
    insp_type: inspTypeMap[r.inspection_type] || '',
    notes: r.notes || '',
  }));
}

return { json: { inspection_id: insp_id, form_num, data: { common, rows } } };

const body = $('PDF Request Webhook').item.json.body;
const form_num = parseInt(body.form_num || 1);
const insp_id = body.inspection_id;
const entityMap = {1:'FireStation',2:'FireExtinguisher',3:'ElectricalPanel',4:'FireDetectionData',5:'ElectricalPanel',6:'EmergencyAnnouncementData',7:'SprinklerData'};
const entity = entityMap[form_num] || 'FireStation';
const rows_url = 'https://avuka.base44.app/api/apps/6980462d4df5bc1deda167e6/entities/' + entity + '?inspection_id=' + insp_id;
return { json: { rows_url, form_num, inspection_id: insp_id } };
